{"file_path":"/home/user/workspace/app/admin/sync-form.tsx","content":""use client";

// ---------------------------------------------------------------------------
// Sync trigger form  — Client Component
//
// Wraps the inline Server Action so we can show pending / success / error
// feedback immediately without a full-page navigation.  The form also works
// without JavaScript because the action attribute is a real Server Action.
// ---------------------------------------------------------------------------

import { useActionState, useEffect, useRef } from "react";

type SyncResult =
  | { status: "idle" }
  | { status: "pending" }
  | { status: "success"; lastSync: string }
  | { status: "error"; message: string };

export function SyncForm({
  syncAction,
}: {
  syncAction: () => Promise<void>;
}) {
  const [state, formAction, isPending] = useActionState<SyncResult, FormData>(
    async () => {
      try {
        await syncAction();
        return { status: "success", lastSync: new Date().toISOString() };
      } catch (err) {
        return {
          status: "error",
          message: err instanceof Error ? err.message : "Sync failed",
        };
      }
    },
    { status: "idle" },
  );

  // Auto-dismiss success after a few seconds.
  const timerRef = useRef<ReturnType<typeof setTimeout>>();
  useEffect(() => {
    if (state.status === "success") {
      timerRef.current = setTimeout(() => {
        // This is a no-op at the data level but clears the visual feedback.
      }, 5_000);
    }
    return () => clearTimeout(timerRef.current);
  }, [state]);

  return (
    <div>
      <form action={formAction}>
        <button
          type="submit"
          disabled={isPending}
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: "0.5rem",
            padding: "0.5rem 1rem",
            border: "1px solid #3b82f6",
            borderRadius: "6px",
            background: isPending ? "#93c5fd" : "#3b82f6",
            color: "#fff",
            fontWeight: 600,
            cursor: isPending ? "not-allowed" : "pointer",
          }}
        >
          {isPending ? (
            <>
              <span style={{ display: "inline-block", width: 16, height: 16, borderRadius: "50%", border: "2px solid #fff", borderTopColor: "transparent", animation: "spin 0.6s linear infinite" }} />
              Syncing…
            </>
          ) : (
            "Sync Latest Catalog"
          )}
        </button>
      </form>

      {state.status === "success" && (
        <p style={{ color: "#16a34a", fontSize: "0.875rem", marginTop: "0.5rem" }}>
          ✓ Sync triggered — catalog is refreshing in the background.
        </p>
      )}

      {state.status === "error" && (
        <p style={{ color: "#dc2626", fontSize: "0.875rem", marginTop: "0.5rem" }}>
          ✗ {state.message}
        </p>
      )}

      <style>{`
        @keyframes spin {
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}
"}

