// ---------------------------------------------------------------------------
// Error boundary for the admin catalog page
//
// Catches errors thrown during server-side rendering or data fetching and
// shows a recoverable state rather than a blank white screen.
// ---------------------------------------------------------------------------

export default function AdminPageError({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  return (
    <div
      style={{
        maxWidth: 960,
        margin: "0 auto",
        padding: "3rem 1rem",
        textAlign: "center",
      }}
    >
      <div
        style={{
          display: "inline-flex",
          alignItems: "center",
          justifyContent: "center",
          width: 56,
          height: 56,
          borderRadius: "50%",
          background: "#fef2f2",
          marginBottom: "1rem",
        }}
      >
        <span style={{ fontSize: 24 }}>⚠</span>
      </div>

      <h1 style={{ fontSize: "1.25rem", fontWeight: 700, margin: 0 }}>
        Something went wrong
      </h1>

      <p style={{ color: "#6b7280", marginTop: "0.5rem", maxWidth: 440, marginInline: "auto" }}>
        The product catalog encountered an error while loading. This may be a
        transient issue with the database or the upstream sync service.
      </p>

      {error.digest && (
        <p style={{ fontSize: "0.75rem", color: "#9ca3af", marginTop: "0.5rem" }}>
          Error digest: {error.digest}
        </p>
      )}

      <button
        onClick={reset}
        style={{
          marginTop: "1.5rem",
          padding: "0.5rem 1.5rem",
          border: "none",
          borderRadius: 6,
          background: "#3b82f6",
          color: "#fff",
          fontWeight: 600,
          cursor: "pointer",
        }}
      >
        Try Again
      </button>
    </div>
  );
}
"}

